const candidate = $input.first().json;
const parsed_resume = typeof candidate.parsed_resume === 'string' 
  ? JSON.parse(candidate.parsed_resume) 
  : candidate.parsed_resume;

const job_title    = $('Webhook').first().json.body.job_title;
const requirements = $('Webhook').first().json.body.requirements;
const kb_context   = $('Webhook').first().json.body.kb_context;

const resume_str = JSON.stringify(parsed_resume, null, 2);
const job_str = JSON.stringify({
  title:        job_title,
  requirements: requirements,
}, null, 2);

const raw_prompt = 
  `Evaluate this candidate:\n\n` +
  `RESUME DATA:\n${resume_str}\n\n` +
  `JOB REQUIREMENTS:\n${job_str}\n\n` +
  `KNOWLEDGE BASE CONTEXT:\n${kb_context}\n\n` +
  `Return ONLY valid JSON. No markdown fences.`;

const user_prompt = raw_prompt
  .replace(/\\n/g, ' ')
  .replace(/\\r/g, ' ')
  .replace(/\r\n/g, ' ')
  .replace(/[ \t]+/g, ' ')
  .trim();

return [{
  json: {
    candidate_id:   $('Webhook').first().json.body.candidate_id,
    application_id: $('Webhook').first().json.body.application_id,
    job_id:         $('Webhook').first().json.body.job_id,
    user_prompt:    user_prompt,
  }
}];

const response = $input.first().json.text;

// Clean and parse
const clean = response
  .replace(/```json/g, '')
  .replace(/```/g, '')
  .replace(/\\n/g, ' ')
  .trim();

let evaluation;
try {
  evaluation = JSON.parse(clean);
} catch(e) {
  throw new Error('Failed to parse AI output: ' + e.message);
}

// Validate score
if (typeof evaluation.score !== 'number' || 
    evaluation.score < 0 || evaluation.score > 100) {
  throw new Error('Invalid score: ' + evaluation.score);
}

// Validate recommendation
const valid_recs = ['Strong Match','Potential Match','Needs Review','Not Qualified'];
if (!valid_recs.includes(evaluation.recommendation)) {
  throw new Error('Invalid recommendation: ' + evaluation.recommendation);
}

// Default empty arrays if missing
evaluation.strengths            = evaluation.strengths || [];
evaluation.weaknesses           = evaluation.weaknesses || [];
evaluation.missing_requirements = evaluation.missing_requirements || [];
evaluation.risk_flags           = evaluation.risk_flags || [];
evaluation.interview_questions  = evaluation.interview_questions || [];

return [{
  json: {
    candidate_id:        $('Build Screening Prompt').first().json.candidate_id,
    application_id:      $('Build Screening Prompt').first().json.application_id,
    job_id:              $('Build Screening Prompt').first().json.job_id,
    score:               evaluation.score,
    recommendation:      evaluation.recommendation,
    strengths:           evaluation.strengths,
    weaknesses:          evaluation.weaknesses,
    missing_requirements: evaluation.missing_requirements,
    risk_flags:          evaluation.risk_flags,
    interview_questions: evaluation.interview_questions,
    recruiter_summary:   evaluation.recruiter_summary,
  }
}];
